1	import { Knex } from 'knex';
2	import { KnexJobRepository } from '../infrastructure/database/repositories/job-repository.js';
3	import { KnexNotificationRepository } from '../infrastructure/database/repositories/notification-repository.js';
4	import { logger } from '../infrastructure/logging/index.js';
5	import { v4 as uuid } from 'uuid';
6	
7	const POLL_INTERVAL = 5000; // 5 seconds
8	const BATCH_SIZE = 5;
9	
10	const TOTAL_SHARDS = 4;
11	
12	export class JobWorker {
13	  private running = false;
14	  private workerId: string;
15	  private shardKeys: number[];
16	  private timer: ReturnType<typeof setInterval> | null = null;
17	
18	  constructor(private db: Knex, shardKeys?: number[]) {
19	    this.workerId = `worker-${uuid().slice(0, 8)}`;
20	    // Default: claim all shards (single-node mode).
21	    // In multi-node deployments, pass explicit shard subsets per worker.
22	    this.shardKeys = shardKeys ?? Array.from({ length: TOTAL_SHARDS }, (_, i) => i);
23	  }
24	
25	  start() {
26	    if (this.running) return;
27	    this.running = true;
28	    logger.info({ workerId: this.workerId, shardKeys: this.shardKeys }, 'Job worker started');
29	
30	    this.timer = setInterval(() => this.poll(), POLL_INTERVAL);
31	  }
32	
33	  stop() {
34	    this.running = false;
35	    if (this.timer) {
36	      clearInterval(this.timer);
37	      this.timer = null;
38	    }
39	    logger.info({ workerId: this.workerId }, 'Job worker stopped');
40	  }
41	
42	  private async poll() {
43	    if (!this.running) return;
44	
45	    try {
46	      const jobRepo = new KnexJobRepository(this.db);
47	      const jobs = await jobRepo.claimJobs(this.workerId, BATCH_SIZE, this.shardKeys);
48	
49	      for (const job of jobs) {
50	        try {
51	          await this.executeJob(job);
52	          await jobRepo.markCompleted(job.id);
53	          logger.info({ jobId: job.id, type: job.type }, 'Job completed');
54	        } catch (err: any) {
55	          await jobRepo.markFailed(job.id, err.message, job.attempts, job.maxAttempts);
56	          logger.error({ jobId: job.id, type: job.type, error: err.message, attempts: job.attempts }, 'Job failed');
57	        }
58	      }
59	    } catch (err) {
60	      logger.error({ err }, 'Job worker poll error');
61	    }
62	  }
63	
64	  private async executeJob(job: any) {
65	    // Idempotency guard: if this job has an idempotency key, check
66	    // whether a completed job with the same key already exists.
67	    if (job.idempotencyKey) {
68	      const existing = await this.db('jobs')
69	        .where({ idempotency_key: job.idempotencyKey, status: 'completed' })
70	        .whereNot({ id: job.id })
71	        .first();
72	      if (existing) {
73	        logger.info({ jobId: job.id, idempotencyKey: job.idempotencyKey }, 'Skipping duplicate job (idempotency key already completed)');
74	        return;
75	      }
76	    }
77	
78	    switch (job.type) {
79	      case 'report-generation':
80	        await this.handleReportGeneration(job);
81	        break;
82	      case 'idempotency-vacuum':
83	        await this.handleIdempotencyVacuum();
84	        break;
85	      case 'record-import':
86	        await this.handleRecordImport(job);
87	        break;
88	      case 'compliance-check':
89	        await this.handleComplianceCheck(job);
90	        break;
91	      default:
92	        throw new Error(`Unknown job type: ${job.type}`);
93	    }
94	  }
95	
96	  private async handleReportGeneration(job: any) {
97	    const { userId, reportType, filters } = job.payload;
98	    const notifRepo = new KnexNotificationRepository(this.db);
99	
100	    await notifRepo.create({
101	      userId,
102	      title: `Report Ready: ${reportType}`,
103	      body: `Your scheduled ${reportType} report has been generated and is ready for viewing.`,
104	      type: 'report_ready',
105	    });
106	  }
107	
108	  private async handleIdempotencyVacuum() {
109	    const deleted = await this.db('idempotency_registry')
110	      .where('expires_at', '<', new Date())
111	      .del();
112	    logger.info({ deleted }, 'Idempotency vacuum completed');
113	  }
114	
115	  private async handleRecordImport(job: any) {
116	    const { source, orgId, batchSize: configuredBatchSize } = job.payload;
117	    const importBatchSize = configuredBatchSize ?? 100;
118	
119	    // Track progress in the job payload
120	    const offset = job.payload.processedCount ?? 0;
121	
122	    logger.info({ jobId: job.id, source, orgId, offset, batchSize: importBatchSize }, 'Record import: processing batch');
123	
124	    // Fetch records to import from the source table
125	    const records = await this.db(source ?? 'users')
126	      .where(orgId ? { org_id: orgId } : {})
127	      .orderBy('created_at', 'asc')
128	      .limit(importBatchSize)
129	      .offset(offset);
130	
131	    if (records.length === 0) {
132	      logger.info({ jobId: job.id, totalProcessed: offset }, 'Record import: all records processed');
133	      return;
134	    }
135	
136	    // Persist incremental progress so retries can resume
137	    const newProcessedCount = offset + records.length;
138	    await this.db('jobs')
139	      .where({ id: job.id })
140	      .update({
141	        payload: JSON.stringify({
142	          ...job.payload,
143	          processedCount: newProcessedCount,
144	          lastBatchSize: records.length,
145	          lastProcessedAt: new Date().toISOString(),
146	        }),
147	      });
148	
149	    logger.info({
150	      jobId: job.id,
151	      batchProcessed: records.length,
152	      totalProcessed: newProcessedCount,
153	    }, 'Record import: batch completed');
154	
155	    // If there are more records, re-enqueue a continuation job
156	    if (records.length >= importBatchSize) {
157	      const jobRepo = new KnexJobRepository(this.db);
158	      await jobRepo.enqueue({
159	        type: 'record-import',
160	        payload: {
161	          ...job.payload,
162	          processedCount: newProcessedCount,
163	        },
164	        priority: job.priority,
165	        orgId: orgId ?? undefined,
166	      });
167	      logger.info({ jobId: job.id }, 'Record import: continuation job enqueued');
168	    }
169	  }
170	
171	  private async handleComplianceCheck(job: any) {
172	    const { orgId, checkType } = job.payload;
173	    const findings: Array<{ entity: string; entityId: string; issue: string; severity: string }> = [];
174	
175	    logger.info({ jobId: job.id, orgId, checkType }, 'Compliance check: starting');
176	
177	    // Check 1: Users with credit score below threshold who have active bookings
178	    if (!checkType || checkType === 'credit_threshold') {
179	      const lowCreditWithBookings = await this.db('users')
180	        .join('bookings', 'users.id', 'bookings.client_id')
181	        .where(orgId ? { 'users.org_id': orgId } : {})
182	        .where('users.credit_score', '<', 20)
183	        .whereIn('bookings.status', ['pending', 'confirmed'])
184	        .select('users.id as userId', 'users.username', 'users.credit_score', 'bookings.id as bookingId')
185	        .distinct();
186	
187	      for (const row of lowCreditWithBookings) {
188	        findings.push({
189	          entity: 'user',
190	          entityId: row.userId,
191	          issue: `User ${row.username} has credit score ${row.credit_score} below threshold with active booking ${row.bookingId}`,
192	          severity: 'warning',
193	        });
194	      }
195	    }
196	
197	    // Check 2: Overdue pending bookings (scheduled in the past, still pending)
198	    if (!checkType || checkType === 'overdue_bookings') {
199	      const overdueBookings = await this.db('bookings')
200	        .where(orgId ? { org_id: orgId } : {})
201	        .where('status', 'pending')
202	        .where('scheduled_at', '<', new Date())
203	        .select('id', 'client_id', 'lawyer_id', 'scheduled_at');
204	
205	      for (const booking of overdueBookings) {
206	        findings.push({
207	          entity: 'booking',
208	          entityId: booking.id,
209	          issue: `Booking is overdue (scheduled ${booking.scheduled_at}) but still pending`,
210	          severity: 'high',
211	        });
212	      }
213	    }
214	
215	    // Check 3: Unresolved disputes past deadline
216	    if (!checkType || checkType === 'expired_disputes') {
217	      const expiredDisputes = await this.db('disputes')
218	        .whereIn('status', ['pending', 'under_review'])
219	        .where('deadline_at', '<', new Date())
220	        .select('id', 'appellant_id', 'deadline_at');
221	
222	      for (const dispute of expiredDisputes) {
223	        findings.push({
224	          entity: 'dispute',
225	          entityId: dispute.id,
226	          issue: `Dispute past deadline (${dispute.deadline_at}) still unresolved`,
227	          severity: 'high',
228	        });
229	      }
230	    }
231	
232	    // Persist findings in job payload for review
233	    await this.db('jobs')
234	      .where({ id: job.id })
235	      .update({
236	        payload: JSON.stringify({
237	          ...job.payload,
238	          findings,
239	          findingsCount: findings.length,
240	          completedAt: new Date().toISOString(),
241	        }),
242	      });
243	
244	    // Notify admins if there are high-severity findings
245	    const highSeverity = findings.filter(f => f.severity === 'high');
246	    if (highSeverity.length > 0 && orgId) {
247	      const admins = await this.db('users')
248	        .where({ org_id: orgId, role: 'admin', is_active: true })
249	        .select('id');
250	
251	      const notifRepo = new KnexNotificationRepository(this.db);
252	      for (const admin of admins) {
253	        await notifRepo.create({
254	          userId: admin.id,
255	          title: 'Compliance Check: Issues Found',
256	          body: `${highSeverity.length} high-severity compliance issue(s) detected. Review the job results for details.`,
257	          type: 'system',
258	          referenceId: job.id,
259	        });
260	      }
261	    }
262	
263	    logger.info({
264	      jobId: job.id,
265	      totalFindings: findings.length,
266	      highSeverity: highSeverity.length,
267	    }, 'Compliance check: completed');
268	  }
269	}
