35	export class KnexJobRepository {
36	  constructor(private db: Knex) {}
37	
38	  async findById(id: string): Promise<Job | null> {
39	    const row = await this.db('jobs').where({ id }).first();
40	    return row ? toDomain(row) : null;
41	  }
42	
43	  async findAll(filters?: { status?: string; type?: string; orgId?: string; page?: number; limit?: number }): Promise<{ data: Job[]; total: number }> {
44	    const page = filters?.page ?? 1;
45	    const limit = filters?.limit ?? 20;
46	
47	    let query = this.db('jobs');
48	    if (filters?.status) query = query.where({ status: filters.status });
49	    if (filters?.type) query = query.where({ type: filters.type });
50	    if (filters?.orgId) query = query.where({ org_id: filters.orgId });
51	
52	    const countResult = await query.clone().count('id as count').first();
53	    const rows = await query.orderBy('created_at', 'desc').limit(limit).offset((page - 1) * limit);
54	    return { data: rows.map(toDomain), total: Number(countResult?.count ?? 0) };
55	  }
56	
57	  async enqueue(input: { type: JobType; payload?: Record<string, unknown>; priority?: number; idempotencyKey?: string; scheduledAt?: Date; orgId?: string; shardKey?: number }): Promise<Job> {
58	    // Compute shard_key deterministically from type + orgId (or idempotencyKey)
59	    const shardKey = input.shardKey ?? computeShardKey(input.type + (input.orgId ?? input.idempotencyKey ?? ''));
60	    const [row] = await this.db('jobs').insert({
61	      type: input.type,
62	      payload: JSON.stringify(input.payload ?? {}),
63	      priority: input.priority ?? 0,
64	      idempotency_key: input.idempotencyKey ?? null,
65	      next_retry_at: input.scheduledAt ?? null,
66	      org_id: input.orgId ?? null,
67	      shard_key: shardKey,
68	    }).returning('*');
69	    return toDomain(row);
70	  }
71	
72	  async claimJobs(workerId: string, batchSize: number = 5, shardKeys?: number[]): Promise<Job[]> {
73	    const shardClause = shardKeys && shardKeys.length > 0
74	      ? `AND shard_key IN (${shardKeys.map(() => '?').join(',')})`
75	      : '';
76	    const params: any[] = [workerId];
77	    if (shardKeys && shardKeys.length > 0) params.push(...shardKeys);
78	    params.push(batchSize);
79	
80	    const rows = await this.db.raw(`
81	      UPDATE jobs SET
82	        status = 'running',
83	        locked_by = ?,
84	        started_at = NOW(),
85	        attempts = attempts + 1
86	      WHERE id IN (
87	        SELECT id FROM jobs
88	        WHERE status IN ('queued', 'failed')
89	          AND attempts < max_attempts
90	          AND (next_retry_at IS NULL OR next_retry_at <= NOW())
91	          ${shardClause}
92	        ORDER BY priority DESC, created_at ASC
93	        FOR UPDATE SKIP LOCKED
94	        LIMIT ?
95	      )
96	      RETURNING *
97	    `, params);
98	
99	    return rows.rows.map(toDomain);
100	  }
101	
102	  async markCompleted(id: string): Promise<void> {
103	    await this.db('jobs').where({ id }).update({
104	      status: 'completed',
105	      completed_at: new Date(),
106	      locked_by: null,
107	    });
108	  }
109	
110	  async markFailed(id: string, error: string, attempts: number, maxAttempts: number): Promise<void> {
111	    const isDead = shouldMarkDead(attempts, maxAttempts);
112	    const nextRetryAt = isDead ? null : new Date(Date.now() + calculateBackoffMs(attempts));
113	
114	    await this.db('jobs').where({ id }).update({
115	      status: isDead ? 'dead' : 'failed',
116	      last_error: error,
117	      next_retry_at: nextRetryAt,
118	      locked_by: null,
119	    });
120	  }
121	}
