20	function sanitizeWebhook(row: any) {
21	  return {
22	    id: row.id,
23	    org_id: row.org_id,
24	    url: row.url,
25	    events: typeof row.events === 'string' ? JSON.parse(row.events) : row.events,
26	    secret: maskSecret(row.secret),
27	    is_active: row.is_active,
28	    created_at: row.created_at,
