95	    const { orgId, role } = request.user;
96	    const targetOrgId = role === 'super_admin' ? (query.orgId || null) : orgId;
97	
98	    let exportQuery = db('bookings');
99	    if (targetOrgId) exportQuery = exportQuery.where('org_id', targetOrgId);
100	    if (query.from) exportQuery = exportQuery.where('created_at', '>=', new Date(query.from));
101	    if (query.to) exportQuery = exportQuery.where('created_at', '<=', new Date(query.to));
102	    if (query.role && targetOrgId) {
103	      const userFilter = db('users').select('id').where({ role: query.role, org_id: targetOrgId });
104	      if (query.role === 'client') {
105	        exportQuery = exportQuery.whereIn('client_id', userFilter);
106	      } else if (query.role === 'lawyer') {
107	        exportQuery = exportQuery.whereIn('lawyer_id', userFilter);
