21	export async function buildServer(): Promise<FastifyInstance> {
22	  const app = Fastify({
23	    logger: false,
24	    trustProxy: true,
25	  });
26	
27	  // CORS — LAN only
28	  await app.register(cors, {
29	    origin: true,
30	    credentials: true,
31	  });
32	
33	  // JWT Auth plugin
34	  await app.register(jwtAuthPlugin);
35	
36	  // Org isolation (RLS enforcement) — must be after jwt-auth
37	  await app.register(orgIsolationPlugin);
38	
39	  // Audit plugin
40	  await app.register(auditPlugin);
41	
42	  // Routes
43	  await app.register(authRoutes);
44	  await app.register(userRoutes);
45	  await app.register(organizationRoutes);
46	  await app.register(availabilityRoutes);
47	  await app.register(bookingRoutes);
48	  await app.register(reviewRoutes);
49	  await app.register(creditRoutes);
50	  await app.register(notificationRoutes);
