8	async function main() {
9	  const config = loadConfig();
10	
11	  // Propagate resolved config (including dev defaults) into process.env
12	  // so modules that read env vars directly (encryption, jwt) get correct values.
13	  process.env.DATABASE_URL = config.database.url;
14	  process.env.JWT_SECRET = config.jwt.secret;
15	  process.env.ENCRYPTION_KEY = config.encryption.key;
16	  process.env.NODE_ENV = config.nodeEnv;
17	
18	  logger.info({ nodeEnv: config.nodeEnv }, 'Starting JusticeOps backend');
19	
20	  // Initialize database
21	  const db = await initDatabase(config.database.url);
22	
23	  // Run migrations
24	  logger.info('Running database migrations...');
25	  await db.migrate.latest();
26	  logger.info('Migrations complete');
27	
28	  // Run seeds in non-production or if DB is empty
29	  // Bypass RLS for counting/seeding
30	  await db.raw("SET app.bypass_rls = 'true'");
31	  const userCount = await db('users').count('id as count').first();
32	  if (!userCount || Number(userCount.count) === 0) {
33	    logger.info('Running database seeds...');
34	    await db.seed.run();
35	    logger.info('Seeds complete');
36	  }
37	
38	  // Build and start server
39	  const app = await buildServer();
40	
41	  // Store config and db on app for plugins to use
42	  app.decorate('config', config);
43	  app.decorate('db', db);
44	
45	  // Start job worker and scheduler
46	  const jobWorker = new JobWorker(db);
47	  const scheduler = new Scheduler(db);
48	  jobWorker.start();
49	  scheduler.start();
50	
51	  try {
52	    await app.listen({ port: config.port, host: '0.0.0.0' });
53	    logger.info({ port: config.port }, 'JusticeOps backend running');
54	  } catch (err) {
55	    logger.error({ err }, 'Failed to start server');
56	    jobWorker.stop();
57	    scheduler.stop();
58	    await closeDatabase();
59	    process.exit(1);
60	  }
61	
62	  // Graceful shutdown
63	  const shutdown = async () => {
64	    logger.info('Shutting down...');
65	    jobWorker.stop();
66	    scheduler.stop();
67	    await app.close();
68	    await closeDatabase();
69	    process.exit(0);
70	  };
71	
72	  process.on('SIGINT', shutdown);
73	  process.on('SIGTERM', shutdown);
74	}
75	
76	main().catch((err) => {
77	  logger.error({ err }, 'Fatal error during startup');
78	  process.exit(1);
