28	export interface TokenSigner {
29	  sign(payload: Record<string, unknown>): string;
30	}
31	
32	const ROLE_PERMISSIONS: Record<string, string[]> = {
33	  client: ['client.dashboard', 'client.bookings', 'client.credit', 'reviews', 'notifications'],
34	  lawyer: ['lawyer.dashboard', 'lawyer.availability', 'lawyer.bookings', 'reviews', 'notifications'],
35	  admin: ['admin.dashboard', 'admin.jobs', 'admin.arbitration', 'admin.users', 'admin.config', 'reports', 'reports.subscriptions', 'notifications'],
36	  super_admin: ['admin.dashboard', 'admin.jobs', 'admin.arbitration', 'admin.users', 'admin.organizations', 'admin.config', 'reports', 'reports.subscriptions', 'notifications'],
37	};
38	
39	export class LoginUseCase {
40	  constructor(
41	    private userRepo: UserRepository,
42	    private sessionRepo: SessionRepository,
43	  ) {}
44	
45	  async execute(input: LoginInput): Promise<LoginResult> {
46	    const user = await this.userRepo.findByUsername(input.username);
47	    if (!user) {
48	      throw new AuthError(401, 'Invalid username or password');
49	    }
50	
51	    if (!user.isActive) {
52	      throw new AuthError(401, 'Account is deactivated');
53	    }
54	
55	    // Check lockout
56	    if (isLockedOut(user)) {
57	      const remaining = getLockoutRemainingSeconds(user.lockedUntil!);
58	      const err = new AuthError(423, `Account locked. Try again in ${remaining} seconds`);
59	      (err as any).retryAfterSeconds = remaining;
60	      throw err;
61	    }
62	
63	    // Verify password
64	    const passwordMatch = await bcrypt.compare(input.password, user.passwordHash);
65	    if (!passwordMatch) {
66	      const newCount = await this.userRepo.incrementFailedAttempts(user.id);
67	      if (shouldLockOut(newCount)) {
68	        const lockoutExpiry = getLockoutExpiry();
69	        await this.userRepo.update(user.id, {
70	          lockedUntil: lockoutExpiry,
71	        });
72	        const remaining = getLockoutRemainingSeconds(lockoutExpiry);
73	        const err = new AuthError(423, `Account locked after ${newCount} failed attempts. Try again in ${remaining} seconds`);
74	        (err as any).retryAfterSeconds = remaining;
75	        throw err;
76	      }
77	      throw new AuthError(401, 'Invalid username or password');
78	    }
79	
80	    // Reset failed attempts
81	    await this.userRepo.resetFailedAttempts(user.id);
82	
83	    // Revoke prior sessions (unless exempt)
84	    if (!user.isSessionExempt) {
85	      await this.sessionRepo.deleteByUserId(user.id);
86	    }
87	
88	    // Create new session
89	    const sessionNonce = uuid();
90	    const jti = uuid();
91	    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24h
92	
93	    await this.sessionRepo.create({
94	      userId: user.id,
95	      sessionNonce,
96	      tokenJti: jti,
97	      ipAddress: input.ipAddress ?? null,
98	      workstationId: input.workstationId ?? null,
99	      expiresAt,
100	    });
101	
102	    return {
103	      user: {
104	        id: user.id,
105	        orgId: user.orgId,
106	        username: user.username,
107	        role: user.role,
108	        creditScore: user.creditScore,
109	      },
110	      sessionNonce,
111	      jti,
112	      menuPermissions: ROLE_PERMISSIONS[user.role] ?? [],
113	      serverTime: new Date().toISOString(),
114	    };
115	  }
116	}
