4	test.describe('Account lockout policy: 5 failures → 15-minute lock', () => {
5	  // Use a dedicated test user to avoid interfering with other tests.
6	  // client2 is seeded and not heavily used elsewhere.
7	  const testUser = 'client2';
8	  const wrongPassword = 'WrongPassword999!';
9	  const correctPassword = 'SecurePass1!';
10	
11	  test('5 consecutive wrong passwords trigger 423 lockout with ~900s retry', async ({ page }) => {
12	    // First, ensure the account is unlocked by logging in successfully
13	    const unlockRes = await page.request.post('/api/auth/login', {
14	      data: { username: testUser, password: correctPassword },
15	    });
16	    // Account may already be locked from a prior run; if 423, wait and retry
17	    if (unlockRes.status() === 423) {
18	      // Skip this test run — account is locked from prior test
19	      test.skip();
20	      return;
21	    }
22	    expect(unlockRes.status()).toBe(200);
23	
24	    // Now send 5 wrong password attempts
25	    for (let i = 1; i <= 5; i++) {
26	      const res = await page.request.post('/api/auth/login', {
27	        data: { username: testUser, password: wrongPassword },
28	      });
29	
30	      if (i < 5) {
31	        // Attempts 1-4: should return 401 (invalid credentials)
32	        expect(res.status()).toBe(401);
33	      } else {
34	        // Attempt 5: should return 423 (account locked)
35	        expect(res.status()).toBe(423);
36	        const body = await res.json();
37	        expect(body.retryAfterSeconds).toBeDefined();
38	        // Should be approximately 900 seconds (15 minutes)
39	        expect(body.retryAfterSeconds).toBeGreaterThanOrEqual(890);
40	        expect(body.retryAfterSeconds).toBeLessThanOrEqual(900);
41	      }
42	    }
43	
44	    // Verify account is now locked — even correct password should fail with 423
45	    const lockedRes = await page.request.post('/api/auth/login', {
46	      data: { username: testUser, password: correctPassword },
47	    });
48	    expect(lockedRes.status()).toBe(423);
49	    const lockedBody = await lockedRes.json();
50	    expect(lockedBody.retryAfterSeconds).toBeGreaterThan(0);
51	  });
52	
53	  test('UI displays lockout countdown when server returns 423', async ({ page }) => {
54	    await page.goto('/login');
55	    await page.evaluate(() => localStorage.clear());
56	
57	    // First ensure account is accessible
58	    const checkRes = await page.request.post('/api/auth/login', {
59	      data: { username: testUser, password: correctPassword },
60	    });
61	    if (checkRes.status() === 423) {
62	      test.skip();
63	      return;
64	    }
65	
66	    // Trigger lockout via 5 wrong attempts through UI
67	    for (let i = 0; i < 5; i++) {
68	      await page.fill('#username', testUser);
69	      await page.fill('#password', wrongPassword);
70	      await page.click('button[type="submit"]');
71	      await page.waitForTimeout(500);
72	    }
73	
74	    // After 5th attempt, UI should show lockout message/countdown
75	    // Look for the lockout text (423 handler shows countdown)
76	    await expect(page.locator('text=/locked|try again/i').first()).toBeVisible({ timeout: 5000 });
77	  });
78	});
