1	import { Injectable, signal, computed } from '@angular/core';
2	import { HttpClient } from '@angular/common/http';
3	import { Router } from '@angular/router';
4	import { LoginResponse, User } from '../models/interfaces';
5	import { NotificationService } from './notification.service';
6	import { TimeSyncService } from './time-sync.service';
7	import { firstValueFrom, ReplaySubject } from 'rxjs';
8	
9	@Injectable({ providedIn: 'root' })
10	export class AuthService {
11	  private tokenKey = 'justiceops_token';
12	  private userKey = 'justiceops_user';
13	  private permissionsKey = 'justiceops_permissions';
14	
15	  currentUser = signal<User | null>(this.loadUser());
16	  isLoggedIn = computed(() => !!this.currentUser());
17	  userRole = computed(() => this.currentUser()?.role ?? null);
18	  menuPermissions = signal<string[]>(this.loadPermissions());
19	
20	  /**
21	   * Emits true once session has been validated against the server,
22	   * or immediately if no stored token exists. Guards await this
23	   * before checking role, so localStorage tampering cannot grant access.
24	   */
25	  private sessionReady$ = new ReplaySubject<boolean>(1);
26	
27	  constructor(private http: HttpClient, private router: Router, private notificationService: NotificationService, private timeSyncService: TimeSyncService) {
28	    if (this.getToken()) {
29	      this.validateSession();
30	    } else {
31	      // No token: clear any stale user/permissions from localStorage
32	      // to prevent tampered justiceops_user from granting UI access.
33	      if (this.currentUser()) {
34	        localStorage.removeItem(this.userKey);
35	        localStorage.removeItem(this.permissionsKey);
36	        this.currentUser.set(null);
37	        this.menuPermissions.set([]);
38	      }
39	      this.sessionReady$.next(true);
40	    }
41	  }
42	
43	  /** Returns a promise that resolves once server-side session validation is complete. */
44	  waitForSessionReady(): Promise<boolean> {
45	    return firstValueFrom(this.sessionReady$);
46	  }
47	
48	  private validateSession() {
49	    this.http.get<{ user: User; permissions: string[] }>('/api/auth/me').subscribe({
50	      next: (res) => {
51	        this.currentUser.set(res.user);
52	        localStorage.setItem(this.userKey, JSON.stringify(res.user));
53	        if (res.permissions) {
54	          this.menuPermissions.set(res.permissions);
55	          localStorage.setItem(this.permissionsKey, JSON.stringify(res.permissions));
56	        }
57	        this.sessionReady$.next(true);
58	      },
59	      error: (err) => {
60	        // Don't clear session on network abort (status 0) — this happens during
61	        // page navigation and would wipe localStorage for the new page load.
62	        if (err?.status === 0) {
63	          this.sessionReady$.next(true);
64	          return;
65	        }
66	        this.clearSession();
67	        this.sessionReady$.next(true);
68	      },
69	    });
70	  }
71	
72	  login(username: string, password: string) {
73	    return this.http.post<LoginResponse>('/api/auth/login', { username, password });
74	  }
75	
76	  handleLoginSuccess(response: LoginResponse) {
77	    localStorage.setItem(this.tokenKey, response.token);
78	    localStorage.setItem(this.userKey, JSON.stringify(response.user));
79	    localStorage.setItem(this.permissionsKey, JSON.stringify(response.menuPermissions));
80	    this.currentUser.set(response.user);
81	    this.menuPermissions.set(response.menuPermissions);
82	    // Login is server-validated by definition
83	    this.sessionReady$.next(true);
84	    // Start time sync for policy timing (e.g., 2-hour cancellation window)
85	    this.timeSyncService.init();
86	  }
87	
88	  logout() {
89	    this.http.post('/api/auth/logout', {}).subscribe({
90	      complete: () => this.clearSession(),
91	      error: () => this.clearSession(),
92	    });
93	  }
94	
