1	import { Component, OnInit, signal } from '@angular/core';
2	import { CommonModule } from '@angular/common';
3	import { RouterModule, ActivatedRoute } from '@angular/router';
4	import { AuthService } from '../../core/services/auth.service';
5	import { TimeSyncService } from '../../core/services/time-sync.service';
6	import { SidebarComponent } from '../sidebar/sidebar.component';
7	import { HeaderComponent } from '../header/header.component';
8	
9	@Component({
10	  selector: 'app-shell',
11	  standalone: true,
12	  imports: [CommonModule, RouterModule, SidebarComponent, HeaderComponent],
13	  template: `
14	    @if (!sessionReady()) {
15	      <div class="loading-shell">
16	        <div class="loading-spinner"></div>
17	      </div>
18	    } @else if (auth.isLoggedIn()) {
19	      <div class="shell-layout">
20	        <app-sidebar />
21	        <div class="shell-main">
22	          <app-header />
23	          @if (timeSync.syncError()) {
24	            <div class="sync-warning">Time sync unavailable — policy timing may be inaccurate.</div>
25	          }
26	          @if (deniedMessage()) {
27	            <div class="permission-denied-banner">
28	              <span>{{ deniedMessage() }}</span>
29	              <button class="dismiss-btn" (click)="dismissDenied()">×</button>
30	            </div>
31	          }
32	          <main class="shell-content">
33	            <router-outlet />
34	          </main>
35	        </div>
36	      </div>
37	    } @else {
38	      <router-outlet />
39	    }
40	  `,
41	  styles: [`
42	    .shell-layout { display: flex; min-height: 100vh; }
43	    .shell-main {
44	      flex: 1;
45	      margin-left: 240px;
46	      display: flex;
47	      flex-direction: column;
48	    }
49	    .shell-content {
50	      flex: 1;
51	      padding: var(--spacing-lg);
52	    }
53	    .permission-denied-banner {
54	      display: flex;
55	      align-items: center;
56	      justify-content: space-between;
57	      background: var(--color-danger, #dc3545);
58	      color: white;
59	      padding: 10px 20px;
60	      font-size: 0.9rem;
61	      font-weight: 500;
62	    }
63	    .dismiss-btn {
64	      background: none;
65	      border: none;
66	      color: white;
67	      font-size: 1.2rem;
68	      cursor: pointer;
69	      padding: 0 4px;
70	    }
71	    .sync-warning {
72	      background: var(--color-warning, #f59e0b);
73	      color: white;
74	      padding: 6px 20px;
75	      font-size: 0.8rem;
76	      text-align: center;
77	    }
78	    .loading-shell {
79	      display: flex;
80	      align-items: center;
81	      justify-content: center;
82	      min-height: 100vh;
83	    }
84	    .loading-spinner {
85	      width: 40px;
86	      height: 40px;
87	      border: 4px solid var(--color-border, #e5e7eb);
88	      border-top-color: var(--color-primary, #2563eb);
89	      border-radius: 50%;
90	      animation: spin 0.8s linear infinite;
91	    }
92	    @keyframes spin { to { transform: rotate(360deg); } }
93	  `]
94	})
95	export class ShellComponent implements OnInit {
96	  deniedMessage = signal<string | null>(null);
97	  sessionReady = signal(false);
98	
99	  constructor(public auth: AuthService, public timeSync: TimeSyncService, private route: ActivatedRoute) {}
100	
101	  ngOnInit() {
102	    // Wait for server session validation before rendering role-dependent chrome
103	    this.auth.waitForSessionReady().then(() => this.sessionReady.set(true));
104	
105	    this.route.queryParams.subscribe(params => {
106	      if (params['denied']) {
107	        this.deniedMessage.set(params['denied']);
108	        setTimeout(() => this.deniedMessage.set(null), 6000);
109	      }
110	    });
111	  }
112	
113	  dismissDenied() {
114	    this.deniedMessage.set(null);
115	  }
116	}
